#!/usr/bin/env bash
# workflow-4.sh — 直播间合规自查 SOP walkthrough for 抖音直播带货 (商家 / 主播 / 直播间运营 + 千川 / 巨量引擎广告投放 + 选品 + 流量场承接 + 合规).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="抖音直播带货 (商家 / 主播 / 直播间运营 + 千川 / 巨量引擎广告投放 + 选品 + 流量场承接 + 合规)"
WORKFLOW="直播间合规自查"

usage() {
  cat <<EOF
workflow-4.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-4.sh             # interactive
  ./workflow-4.sh --dry-run
  ./workflow-4.sh --json
  ./workflow-4.sh --explain
  ./workflow-4.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "直播间合规自查" 工作流。

一句话: 从「准备开播 / 监管或平台规则更新」到「产出一份过了红线检查、可安全开播的合规清单」的工作流 —— 强监管行业的必备工作流，「能不能做」先于「怎么做」。

入门 SOP 共 5 步, 失败模式自检 5 项。

相关心智模型:
  • 算法生意：直播间是做给算法看的，不是做给用户看的: 抖音直播带货的本质是「向推荐算法证明这个直播间值得被推流」——理解算法如何用停留 / 转化 / GPM 这组指标分配免费流量，比话术技巧更底层；流量是非线性「大爆发」的，核心变量是流量 × 选品。
  • 承接 > 引流：流量是放大器不是发动机: 直播间能不能做起来，发动机是「承接能力」(UV 价值 / 停留时长 / GPM / 品组 / 话术)，流量 (自然 + 投流) 只是把这台发动机的输出放大——承接是负数时，加流量等于加速亏钱。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**绝对化用语自查**: 检查话术里有没有「全网最低价/最好/第一/唯一/史上最低」等《广告法》第九条禁用的绝对化用语，改为「直播间专享价」等。**跳过会发生什么**：被市监部门处罚（已多案被罚），账号也暴露「未受合规培训」。 evidence: [T03-S011, T03-S012]"
  "**资质与信息公示自查**: 检查账号主页/直播页面是否持续公示真实名称、社会信用代码、经营地址、联系方式（2026 新规强制）；专业领域（医疗/财经/法律/教育）主播是否持执业资质并报备。**跳过会发生什么**：违反 2026 新规信息公示义务，处罚 + 黑名单风险。 evidence: [T03-S011, T03-S012]"
  "**禁限商品 + 虚假宣传自查**: 检查所选商品是否在平台「负面目录」/地方禁限商品目录内；讲款话术有无夸大功效、虚假承诺。**跳过会发生什么**：售假/虚假宣传触发退一赔三、平台限流。 evidence: [T03-S011]"
  "**AI 数字人标识自查**: 若用 AI 生成虚拟主播，必须做显著标识并持续提示（2026 新规强制）。**跳过会发生什么**：违反 2026 新规 AI 标识义务。 evidence: [T03-S011]"
  "**售后承诺自查**: 检查直播间承诺的售后（退换/赔付）是否能落地「首问负责/先行赔付」。**跳过会发生什么**：售后承诺兑现不了引发投诉、违反 2026 新规售后追责。 evidence: [T03-S011]"
)
declare -a FAILURE_MODES=(
  "**直播间张口喊「全网最低价」**: 触发原因 —— 主播没受过合规培训、沿用老话术。后果 —— 《广告法》第九条违规被罚。怎么避免：**话术里所有绝对化用语（最低/最好/第一/唯一）全部替换为「直播间专享价」类合规表述，开播前逐句过一遍**。 evidence: [T03-S011, T03-S012]"
  "**以为「主播只是帮忙吆喝、不担责」**: 触发原因 —— 不懂主播法律身份认定。后果 —— 出问题时被认定为广告代言人/经营者，承担行政处罚/连带赔偿/三倍赔偿。怎么避免：**开播前明确主播在本场的法律身份（是否亲自使用商品、是否与品牌直接签约），按身份预判责任**。 evidence: [T03-S011]"
  "**AI 数字人直播不标识**: 触发原因 —— 不知道 2026 新规要求。后果 —— 违反 AI 标识义务被处罚。怎么避免：**用 AI 虚拟主播必须全程显著标识「AI 生成」**。 evidence: [T03-S011]"
  "**用旧规则裸奔**: 触发原因 —— 不跟监管更新。后果 —— 2026-02 新规生效后还按老办法做，踩新增红线。怎么避免：**监管/平台规则一更新就重校自查清单，把抖音电商学习中心「规则中心」当固定信息源**。 evidence: [T03-S011]"
  "**CLI 化暗示 (v0.6+)**: 可抽进 \`cli/workflow/compliance-check.sh\`，每条变 yes/no（如「你的话术里还有『全网最低价』这类词吗？」「用了 AI 数字人吗？标识了吗？」「这是按 2026-02 后的新规自查的吗？」）。这个 workflow 的 CLI 化价值最高 —— 红线检查最适合做强制 yes/no 确认。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-4-walkthrough"
fi
